.theme-toggle:hover {
    transform: scale(1.1);
}

/* Dark theme specific styles */
body.dark-theme .container {
    background: #2c2c2e;
    color: #f5f5f7;
}

body.dark-theme textarea {
    background: #1c1c1e;
    color: #f5f5f7;
    border-color: #3a3a3c;
}

body.dark-theme .action-button {
    background-color: #34C759;
}

body.dark-theme .action-button:hover {
    background-color: #248a3d;
}

body.dark-theme .notice-banner {
    background-color: #3a2e00;
    color: #ffd93d;
    border-color: #664d00;
}

body.dark-theme .action-button:disabled {
    background-color: #666666;
    color: #cccccc;
}

body.dark-theme .action-button:disabled:hover {
    background-color: #666666;
}

/* index_test layout helpers */
.status-stack {
    text-align: center;
    margin: 10px 0 16px 0;
}

.status-label {
    font-weight: 600;
    margin-bottom: 6px;
}

.timer-label {
    font-size: 1.1rem;
    letter-spacing: 0.5px;
}

.controls-stack {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
    margin-bottom: 8px;
}

.primary-control {
    display: flex;
    justify-content: center;
}

.secondary-actions {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
}

.replay-button {
    min-width: 160px;
}

.storage-hint {
    font-size: 0.95rem;
    color: #666;
}

body.dark-theme .storage-hint {
    color: #ccc;
}
